(window.webpackJsonp=window.webpackJsonp||[]).push([[6],{"4b/M":function(e,o,a){e.exports=a.p+"static/panorama-9a226b259d5e7d350b731648aea89f8a.jpg"},"5Epl":function(e,o,a){"use strict";a.d(o,"a",(function(){return s}));var i=a("q1tI"),n=a.n(i),r=a("R/WZ"),t=a("ofer"),l=Object(r.a)({figure:{margin:"0"},image:{width:"100%",maxHeight:"700px",borderRadius:"7px",display:"block",margin:"auto"}});function s(e){var o=e.src,a=e.caption,i=e.center,r=l();return n.a.createElement("figure",{className:r.figure},n.a.createElement("img",{src:o,alt:a,className:r.image,style:i?{width:"auto",margin:"auto"}:null}),n.a.createElement(t.a,{variant:"caption",paragraph:!0,align:i?"center":"left"},a))}},6712:function(e,o,a){e.exports=a.p+"static/pot1-0e8b02557db1a0d79ca4c13a7a61e8b3.jpg"},RXBc:function(e,o,a){"use strict";a.r(o);var i=a("q1tI"),n=a.n(i),r=a("ofer"),t=a("mc/u"),l=a("5Epl"),s=a("4b/M"),j=a.n(s),p=a("6712"),d=a.n(p);o.default=function(){return n.a.createElement(t.a,null,n.a.createElement(r.a,{variant:"body1",paragraph:!0},"Cvinger pri Dolenjskih Toplicah je eno najpomembnejših starejšeželeznodobnih središč v Sloveniji in širšem jugovzhodnem predalpskem prostoru. Najdišče, ki leži na odlični strateški lokaciji, je v naravi predstavljeno kot arheološki park. Njegove najpomembnejše gradnike povezuje arheološka pot, s čimer prazgodovinsko dediščino predstavlja v izvirnem okolju. Arheološko najdišče Cvinger sestavlja več arheoloških območij, ki jih moramo razumeti kot neločljivo povezano celoto. Osrednji del je prazgodovinsko gradišče, ki je obdano z nekoč mogočnim obzidjem in je v krajšem segmentu delno rekonstruirano. Na njegovem južnem pobočju se razteza talilniško območje, na katerem so staroselci v več sto talilnih pečeh pridobivali železo. Tega so nato s kovanjem predelovali v orodje, orožje in nakit ter druge uporabne izdelke, s katerimi so trgovali v širšem prostoru. Vsebinsko celoto najdišča zaključujejo gomilna grobišča, kjer so v številnih zemljenih gomilah skupaj z grobnimi pridatki pokopani nekdanji pripadniki tukajšnje dolenjske prazgodovinske skupnosti."),n.a.createElement(l.a,{src:j.a,caption:"Cvinger s prazgodovinskim gradiščem (v sredini) se dviguje nad sotočjem Krke in Radeščice."}),n.a.createElement(r.a,{variant:"body1",paragraph:!0},"Najstarejši deli najdišča sodijo v pozno bronasto dobo oziroma v začetek starejše železne dobe (10.–8. stoletje pr. n. št.). Njej sledi prekinitev poselitve, ki je trajala več stoletij vse do mladohalštatskega obdobja (6.–4. stoletje pr. n. št.), ko je Cvinger dosegel višek svoje moči. Ohranjeni materialni ostanki in izjemne arheološke najdbe nam zgovorno pričajo o pomenu in gospodarski moči skupnosti, ki je pred poltretjim tisočletjem sooblikovala evropski kulturni prostor in neizbrisno obogatila zakladnico evropske kulturne dediščine."),n.a.createElement(l.a,{src:d.a,caption:"Steze, po katerih poteka arheološka pot, se vijejo po mešanem gozdu."}),n.a.createElement(r.a,{variant:"body1",paragraph:!0},"Najdišče je kot enota kulturne dediščine Dolenjske Toplice ‒ Arheološko najdišče Cvinger (EŠD 110) vpisano v register kulturne dediščine. Status kulturnega spomenika je z občinskim odlokom pridobilo že leta 1992. Današnjo pravno zaščito temu kulturnemu spomeniku zagotavlja Odlok o razglasitvi nepremičnih kulturnih spomenikov lokalnega pomena na območju Občine Dolenjske Toplice iz leta 2018."),n.a.createElement(r.a,{variant:"body1",paragraph:!0},"Zaradi svojega regionalnega pomena je bil Cvinger kot železarsko središče vključen v več mednarodnih raziskovalnih in promocijskih projektov. V sklopu projekta Iron Age Danube je bila tako med drugimi obnovljena tudi pričujoča arheološka pot, ki jo je moč skupaj s še nekaterimi potmi v okolici obiskati tudi s pomočjo spletnega vodiča (Guide@Hand). Ob tem je Cvinger tudi eno pomembnejših najdišč Železnodobne poti po Podonavju (Iron Age Danube Route), ki povezuje najpomembnejša najdišča iz tega obdobja v širši podonavski regiji."))}}}]);
